// JavaScript
import '@maersk-global/mds-components-core/mc-modal';
import '@maersk-global/mds-components-core/mc-button';
import '@maersk-global/mds-components-core/mc-toast';
import '@maersk-global/mds-components-core/mc-notification';
import '@maersk-global/mds-components-core/mc-input';
import '@maersk-global/mds-components-core/mc-input-date';

const toggleModal = () => {
  const mcModal: IMcModal = document.body.querySelector('mc-modal') as IMcModal;
  mcModal.open = true;
};
const toggleToast = () => {
  const toast = document.body.querySelector('mc-toast');
  toast.open = true;
};

const mcButtonOpenModal = document.getElementById('openModal') as HTMLButtonElement;
mcButtonOpenModal.addEventListener('click', () => toggleModal());

const mcButtonShowToast = document.getElementById('showToast') as HTMLButtonElement;
mcButtonShowToast.addEventListener('click', () => toggleToast());

// HTML
<mc-toast duration="5000" appearance="info">
  <mc-notification body="Toast body text"></mc-notification>
</mc-toast>
<mc-button id="openModal">Open modal</mc-button>
<mc-modal heading="Heading" customstacking>
